                "InnerHeader": "Code File: \"Level.java\"",
                "InnerBody": "//This is the class \"Level\" from Olympus that houses important information about the levels in the game, including how to change terrain in the current level map\r\n\r\nimport java.awt.Graphics2D;\r\nimport java.awt.image.BufferedImage;\r\nimport java.io.IOException;\r\n\r\npublic class Level {\r\n\t//The level's size\r\n\tprivate int horSize;\r\n\tprivate int verSize;\r\n\t//Level general information\r\n\tprivate final Terrain levelTerrain;\t//The single instance of the inner class that contains the level's map\r\n\tstatic Graphics2D tilePaste;\t//Graphic objects used to alter the level's maps\r\n\tprivate String levelInfo;\r\n\tprivate String levelFile;\r\n\r\n\tpublic Level(String levelFile) throws IOException {\r\n\t\tthis.levelFile = levelFile;\r\n\r\n\t\tlevelInfo = ReadDataFile.getFileData(levelFile, \"LevelInfo\");\r\n\t\t//The level's name is found at the beginning of the data file, and it ends with a '#'\r\n\t\twhile(true) {\r\n\t\t\tif (levelInfo.charAt(0) == '#')\r\n\t\t\t\tbreak;\r\n\t\t\tlevelInfo = levelInfo.substring(1);\r\n\t\t}\r\n\t\tlevelInfo = levelInfo.substring(2);\r\n\r\n\t\t//This retrieves the level's general information from the data file\r\n\t\thorSize = Integer.parseInt(levelInfo.split(\" \")[0]);\r\n\t\tverSize = Integer.parseInt(levelInfo.split(\" \")[1]);\r\n\r\n\t\t//Creates a single instance of the inner class\r\n\t\tlevelTerrain = new Terrain(horSize,verSize);\r\n\t}\r\n\t\r\n\t//Getter methods for various general level info\r\n\tpublic int getX() {\r\n\t\treturn horSize;\r\n\t}\r\n\tpublic int getY() {\r\n\t\treturn verSize;\r\n\t}\r\n\t\r\n\t//Get the level's graphic maps from this class\r\n\tpublic BufferedImage getMap() {\r\n\t\treturn levelTerrain.levelMap;\r\n\t}\r\n\t\r\n\t//This calls the inner class' method to change the graphic map\r\n\tpublic void changeTile(int xPos, int yPos, char changeTo, boolean makingEntireMap) {\r\n\t\tlevelTerrain.changeTile(xPos, yPos, changeTo, makingEntireMap);\r\n\t}\r\n\t\t\r\n\t//The inner class \"Terrain\" which contains the map of the level's walls, floors, etc. \r\n\tprivate class Terrain {\r\n\t\tprivate BufferedImage levelMap;\t//The big map in the editing window\r\n\t\t\t\r\n\t\t//This constructs the Terrain object and \r\n\t\tprivate Terrain(int hSize, int vSize) throws IOException {\r\n\t\t\t//Graphic representation of the level's terrain, as well as text representation that is read from or written to the file\r\n\t\t\tlevelMap = new BufferedImage(hSize * 50, vSize * 50, BufferedImage.TYPE_INT_RGB);\r\n\t\t\t//The Graphics instance used to change the level graphic map\r\n\t\t\ttilePaste = levelMap.createGraphics();\t\t\t\r\n\t\t\t\r\n\t\t\t//Information gotten from the level's data file for the level's terrain\r\n\t\t\tString mapTerrainData = ReadDataFile.getFileData(levelFile, \"MapTerrain\");\r\n\r\n\t\t\t//Create the text representation of the map, and start pasting tiles into the graphic map\r\n\t\t\tint currentChar = 0;\r\n\t\t\tfor (int currentY = 0; currentY &lt vSize; currentY++) {\r\n\t\t\t\tcurrentChar++;\r\n\t\t\t\tfor (int currentX = 0; currentX &lt hSize; currentX++) {\r\n\t\t\t\t\tchangeTile(currentX, currentY, mapTerrainData.charAt(currentChar),true);\r\n\t\t\t\t\tcurrentChar++;\r\n\t\t\t\t}\r\n\t\t\t}\r\n\t\t\ttilePaste.dispose();\t//close the Graphics instance\r\n\t\t}\r\n\t\t\r\n\t\t//This method changes squares in the graphic map, as well as the characters in the text representation\r\n\t\tprivate void changeTile(int xPos, int yPos, char changeTo, boolean makingEntireMap) {\r\n\t\t\t//This determines if the whole map is being made, or just to change a single tile\r\n\t\t\tif (makingEntireMap == false)\r\n\t\t\t{\r\n\t\t\t\ttilePaste = levelMap.createGraphics();\t//initialize the Graphics object to change a single square tile on the map\r\n\t\t\t}\r\n\t\t\t//This does the drawing, getting map tile picture from built in file\r\n\t\t\ttilePaste.drawImage(TerrainTiles.getPict(changeTo), xPos * 50 + 1, yPos * 50 + 1, 48, 48, null);\r\n\t\t\tif (makingEntireMap == false) {\r\n\t\t\t\ttilePaste.dispose();\t//close the Graphics instance\r\n\t\t\t}\r\n\t\t}\r\n\t}\r\n\t\r\n}\r\n"
